import React, { useState } from "react";

import Crad from "../../shared/components/UIElements/Card";
import './Auth.css';
import Input from "../../shared/components/FormElements/Input";
import Button from "../../shared/components/FormElements/Button";
import { VALIDATOR_EMAIL,VALIDATOR_MINLENGTH,VALIDATOR_REQUIRE } from "../../shared/components/util/validators";
import { useForm } from "../../shared/components/hooks/form-hook"; 

const Auth = () => {
    const [isLoginMode, setIsLoginMode] = useState(true);
  const [formState,inputHandler] = useForm({
        email:{
            value: '',
            isvalid: false
        },
        password:{
            value:'',
            isvalid: false
        }
    }, false);

     const switchModeHandler = () => {
        setIsLoginMode(prevMode => !prevMode);
     };
const authSubmitHandler = event => {
    event.preventDefault();
    console.log(formState.inputs);
};

    return <Crad className="authentication">
        <h2>Login Required</h2>
        <hr/>
        <form onSubmit={authSubmitHandler}>
            {!isLoginMode && <Input
             element="input"
              id="name" 
              type="text" 
              label=" Your Name" 
              validators ={[VALIDATOR_REQUIRE]}
              errorText="Please enter a name."
              onInput={inputHandler}
              />}
           <Input
            element="input" 
           id="email"
            type="email"
             label="E-Mail"
              validators={[VALIDATOR_EMAIL()]} 
              errorText="Please enter a vaild email address."
          onInput={inputHandler}
        />
        <Input
            element="input" 
           id="password"
            type="password"
             label="password"
              validators={[VALIDATOR_MINLENGTH(5)]} 
              errorText="Please enter a vaild password,at least 5 characters."
          onInput={inputHandler}
        />
        <Button type="submit" disabled={!formState.isValid}>
            {isLoginMode ? 'LOGIN' : 'SIGNUP'}
        </Button>
        </form>
        <Button inverse onClick={switchModeHandler}
        >SWITCH TO {isLoginMode ? 'SIGNUP' : 'LOGIN'}</Button>
        </Crad>;
};

export default Auth;
